// Package clients contains Connect client adapters for peer services.
package clients

import (
	"context"
	"net/http"

	"connectrpc.com/connect"

	// Generated by buf generate
	yieldv1 "p9e.in/samavaya/agriculture/yield-service/api/v1"
	yieldv1connect "p9e.in/samavaya/agriculture/yield-service/api/v1/yieldv1connect"
	"p9e.in/samavaya/agriculture/traceability-service/internal/ports/outbound"
)

type yieldClient struct {
	client yieldv1connect.YieldServiceClient
}

// NewYieldClient creates a Connect-backed YieldClient.
func NewYieldClient(baseURL string, httpClient *http.Client, opts ...connect.ClientOption) outbound.YieldClient {
	return &yieldClient{
		client: yieldv1connect.NewYieldServiceClient(httpClient, baseURL, opts...),
	}
}

func (c *yieldClient) YieldExists(ctx context.Context, uuid, tenantID string) (bool, error) {
	resp, err := c.client.GetYield(ctx, connect.NewRequest(&yieldv1.GetYieldRequest{Id: uuid}))
	if err != nil {
		return false, nil
	}
	return resp.Msg.GetYield() != nil, nil
}

func (c *yieldClient) GetYieldRecord(ctx context.Context, fieldUUID, tenantID string) (float64, error) {
	resp, err := c.client.GetYieldRecord(ctx, connect.NewRequest(&yieldv1.GetYieldRecordRequest{FieldId: fieldUUID}))
	if err != nil {
		return 0, err
	}
	return resp.Msg.GetActualYieldKgPerHectare(), nil
}
